#!/usr/bin/env node
/**
 * gen-structure-glbs — author one distinct GLB per structure kind for the
 * Plan-stage `DesignElementScenegraphLayer` (deck.gl).
 *
 * Phase 2 of ADR `2026-05-11-atlas-deckgl-scenegraph-migration.md`. Replaces
 * the single shared `_generic_box.glb` (which every kind currently points
 * at) with per-kind procedural meshes that give each catalog entry its own
 * silhouette in 3D.
 *
 * All output is CC0 — meshes are generated by code in this repo, not lifted
 * from external asset packs. See `public/models/structures/NOTICE.md`.
 *
 * Conventions (matching `_generic_box.glb`):
 *   - Unit-normalized: X/Z in [-0.5, 0.5], Y in [0, 1]
 *   - Base-centre anchored — deck.gl `getScale` stretches X/Y/Z to the
 *     kind's footprintM × heightM × footprintM
 *
 * Run via:    pnpm --filter @ogden/web gen:models
 */

import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { writeGLB } from './lib/glb-writer.mjs';
import { box, pitchedBox, cylinder, cone, dome, disc, merge } from './lib/primitives.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUT_DIR = join(__dirname, '..', 'public', 'models', 'structures');

// ── Per-kind authored shapes ────────────────────────────────────────────
// Each builder returns a unit-normalized mesh. Colors approximate the
// material's nominal hue; ScenegraphLayer renders these straight (PBR
// uses authored materials — see ADR).
const KINDS = {
  // Yurt: cylindrical walls + conical roof.
  yurt: {
    color: [0.93, 0.85, 0.62],
    build: () => merge([
      cylinder(0.45, 0.6, 20, 0),         // walls 0..0.6
      cone(0.5, 0.4, 20, 0.6),            // roof apex 0.6..1.0
    ]),
  },

  // Greenhouse: pitched-roof box, low walls, broad ridge.
  greenhouse: {
    color: [0.78, 0.92, 0.92],
    build: () => pitchedBox(1.0, 1.0, 0.55, 0.45),
  },

  // Barn: pitched-roof box, taller walls, steeper roof.
  barn: {
    color: [0.65, 0.22, 0.18],
    build: () => pitchedBox(1.0, 1.0, 0.6, 0.4),
  },

  // Shed: simple box (slightly narrower than full unit so it reads as
  // smaller than a barn at the same footprint).
  shed: {
    color: [0.55, 0.4, 0.25],
    build: () => box(0.9, 1.0, 0.9),
  },

  // Machinery shed: wide pitched-roof box, low pitch — long machinery bay.
  'machinery-shed': {
    color: [0.5, 0.5, 0.55],
    build: () => pitchedBox(1.0, 1.0, 0.7, 0.3),
  },

  // Fuel station: pump box at centre + wide flat canopy above on a
  // single central column. Reads at a glance as "covered pumps."
  'fuel-station': {
    color: [0.92, 0.62, 0.18],
    build: () => merge([
      box(0.5, 0.5, 0.5),                  // pump housing 0..0.5
      box(0.1, 0.4, 0.1, 0.5),             // column 0.5..0.9
      box(1.0, 0.1, 0.8, 0.9),             // canopy slab 0.9..1.0
    ]),
  },

  // Equipment yard: thin slab (gravel pad).
  'equipment-yard': {
    color: [0.45, 0.45, 0.4],
    build: () => box(1.0, 1.0, 1.0),       // unit cube — heightM=0.3 gives a thin slab via scale
  },

  // Water tank: tall capped cylinder.
  'water-tank': {
    color: [0.7, 0.78, 0.85],
    build: () => cylinder(0.4, 1.0, 20),
  },

  // Pond: thin disc, slightly inset so the rim reads.
  pond: {
    color: [0.3, 0.55, 0.85],
    build: () => disc(0.5, 1.0, 24),       // heightM=0, baseM=-0.8 in registry → flat depression
  },

  // Spring: small dome.
  spring: {
    color: [0.4, 0.7, 0.95],
    build: () => dome(0.5, 1.0, 20, 8),
  },

  // Prayer pavilion: square base + larger smoothed dome.
  'prayer-pavilion': {
    color: [0.95, 0.9, 0.82],
    build: () => merge([
      box(1.0, 0.5, 1.0),                  // base 0..0.5
      dome(0.5, 0.5, 24, 10, 0.5),         // dome 0.5..1.0
    ]),
  },

  // Parking: flat slab (asphalt).
  parking: {
    color: [0.25, 0.25, 0.28],
    build: () => box(1.0, 1.0, 1.0),
  },

  // Fire circle: low capped cylinder.
  'fire-circle': {
    color: [0.42, 0.25, 0.18],
    build: () => cylinder(0.5, 1.0, 16),
  },

  // Compost: smaller cube (heightM/footprintM in registry are small).
  compost: {
    color: [0.32, 0.22, 0.12],
    build: () => box(1.0, 1.0, 1.0),
  },
};

// ── Run ──────────────────────────────────────────────────────────────────
let totalBytes = 0;
let totalKinds = 0;
for (const [kind, spec] of Object.entries(KINDS)) {
  const mesh = spec.build();
  const outPath = join(OUT_DIR, `${kind}.glb`);
  const stats = writeGLB(
    {
      positions: mesh.positions,
      normals: mesh.normals,
      indices: mesh.indices,
      color: spec.color,
      name: kind,
    },
    outPath,
  );
  console.log(
    `wrote ${outPath} (${stats.bytes} bytes, ${stats.vertexCount} verts, ${stats.triangleCount} tris)`,
  );
  totalBytes += stats.bytes;
  totalKinds += 1;
}
console.log(`\n${totalKinds} kinds, ${totalBytes} bytes total`);
